SELECT /*+ INDEX_DESC(A PPS_CODE_AGENT_RCG_AUTO_IDX1)*/ SOC, F_GET_CODE_AGENT_RCG_AUTO_NM('SOC', SOC) SOC_NM, AGENT_ID, F_GET_CODE_AGENT_RCG_AUTO_NM('AGENT_ID', AGENT_ID) AGENT_NM, CUST_IDNT_NO_IND_CD, F_GET_CODE_AGENT_RCG_AUTO_NM('CUST_IDNT_NO_IND_CD', CUST_IDNT_NO_IND_CD) CUST_IDNT_NO_IND_CD_NM, REQ_TYPE, F_GET_CODE_AGENT_RCG_AUTO_NM('REQ_TYPE', REQ_TYPE) REQ_TYPE_NM, AMOUNT, F_GET_CODE_AGENT_RCG_AUTO_NM('AMOUNT', TO_CHAR(AMOUNT)) AMOUNT_NM, REMARK, TO_CHAR(REG_DT, 'YYYY-MM-DD HH24:MI:SS') REG_DT, TO_CHAR(MOD_DT, 'YYYY-MM-DD HH24:MI:SS') MOD_DT, ADMIN_ID, F_GET_ADMIN_NM(ADMIN_ID) ADMIN_NM, CASE WHEN SOC = 'PPS35' THEN 'Y' WHEN (SELECT 'Y' FROM PPS_CODE_SERVICE_TOPUP WHERE SOC = A.SOC AND KT_MODE <> 'TOPUP_REFILL' AND ROWNUM = 1) = 'Y' THEN 'Y' ELSE 'N' END PPS35_FLAG FROM PPS_CODE_AGENT_RCG_AUTO A WHERE 1=1
