AND REG_DT < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND SOC = #{searchSoc}
AND REQ_TYPE = #{searchReqType}
AND CUST_IDNT_NO_IND_CD = #{searchCustIdntNoIndCd}
AND AGENT_ID = #{searchAgentId}

